import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { MPerson, MFamily, MFact, build, run } from '../../__tests__/test-helper'
import { Card, Match } from '../../config/Util'
import { PersonNode } from '../PersonNode'
import { FamilyNode } from '../FamilyNode'
import { Bond } from '../Bond'

describe('Node behavior', () => {
  it('PersonNode centerRelX is width/2', () => {
    const p = new MPerson('Test /A/')
    const { graph, fulcrum } = build(p)
    run(graph, fulcrum)
    for (const pn of graph.animator.personNodes) {
      assert.equal(pn.centerRelX(), pn.width / 2, `centerRelX=${pn.centerRelX()}, width/2=${pn.width / 2}`)
    }
  })

  it('PersonNode centerRelY is height/2', () => {
    const p = new MPerson('Test /B/')
    const { graph, fulcrum } = build(p)
    run(graph, fulcrum)
    for (const pn of graph.animator.personNodes) {
      assert.equal(pn.centerRelY(), pn.height / 2)
    }
  })

  it('isFulcrumNode true only for fulcrum', () => {
    const parent = new MPerson('Parent /C/')
    const spouse = new MPerson('Spouse /C/')
    const fulcrumPerson = new MPerson('Fulcrum /C/')
    new MFamily([parent], [spouse], [fulcrumPerson])
    const { graph, fulcrum } = build(fulcrumPerson, parent, spouse)
    run(graph, fulcrum)
    for (const pn of graph.animator.personNodes) {
      if (pn.person.getId() === fulcrumPerson.getId()) {
        assert.ok(pn.isFulcrumNode(), 'fulcrum is fulcrum')
      } else {
        assert.equal(pn.isFulcrumNode(), false, 'non-fulcrum is not')
      }
    }
  })

  it('dead flag set when DEAT or BURI fact exists', () => {
    const dead1 = new MPerson('Dead /D/', [new MFact('DEAT', 'Y')])
    const dead2 = new MPerson('Buried /D/', [new MFact('BURI', '')])
    const alive = new MPerson('Alive /D/', [])
    for (const p of [dead1, dead2, alive]) {
      const { graph, fulcrum } = build(p)
      run(graph, fulcrum)
      const node = graph.animator.personNodes.find(n => n.person.getId() === p.getId())
      assert.ok(node, 'node exists')
      if (p === dead1 || p === dead2) {
        assert.ok(node!.dead, 'dead flag true')
      } else {
        assert.equal(node!.dead, false, 'dead flag false')
      }
    }
  })

  it('duplicate flag set for duplicate PersonNode', () => {
    const grandfather = new MPerson('Grandpa /E/')
    const grandmother = new MPerson('Grandma /E/')
    const dad = new MPerson('Dad /E/')
    const aunt = new MPerson('Aunt /E/')
    const mom = new MPerson('Mom /E/')
    const uncle = new MPerson('Uncle /E/')
    const fulcrumPerson = new MPerson('Fulcrum /E/')
    const spouse = new MPerson('Spouse /E/')
    const child = new MPerson('Child /E/')
    new MFamily([grandfather], [grandmother], [dad, aunt])
    new MFamily([dad], [mom], [fulcrumPerson])
    new MFamily([uncle], [aunt], [spouse])
    new MFamily([fulcrumPerson], [spouse], [child])
    const { graph, fulcrum } = build(fulcrumPerson, spouse, child, grandfather, grandmother, dad, aunt, mom, uncle)
    run(graph, fulcrum)
    const dups = graph.animator.personNodes.filter(n => n.duplicate)
    assert.ok(dups.length > 0, 'at least one duplicate')
  })

  it('acquired flag set for in-law ancestors', () => {
    const parent = new MPerson('Parent /F/')
    const spouse = new MPerson('Spouse /F/')
    const fulcrumPerson = new MPerson('Fulcrum /F/')
    new MFamily([parent], [spouse], [fulcrumPerson])
    const { graph, fulcrum } = build(fulcrumPerson, parent, spouse)
    graph.displayNumbers(true)
    run(graph, fulcrum)
    const acquired = graph.animator.personNodes.filter(n => n.acquired)
    if (acquired.length > 0) {
      for (const a of acquired) {
        assert.ok(
          a.origin !== null || a.type === Card.ANCESTRY,
          `acquired node ${a.person.getId()} should have origin or be ancestry`,
        )
      }
    }
  })

  it('PersonNode setX updates force and x', () => {
    const pn = new PersonNode({} as any, new MPerson('Force /G/'), Card.REGULAR)
    pn.x = 10
    pn.force = 0
    pn.setX(20)
    assert.equal(pn.x, 20)
    assert.equal(pn.force, 10)
  })

  it('PersonNode setY updates y', () => {
    const pn = new PersonNode({} as any, new MPerson('YTest /H/'), Card.REGULAR)
    pn.setY(42)
    assert.equal(pn.y, 42)
  })

  it('FamilyNode setX updates partners and bond position', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    fn.bond = new Bond(fn)
    fn.bond.width = 10
    const pn = new PersonNode({} as any, new MPerson('Partner /I/'), Card.REGULAR)
    pn.width = 50
    fn.partners = [pn]
    fn.setX(100)
    assert.equal(fn.x, 100)
    assert.equal(pn.x, 100)
  })

  it('FamilyNode getMainPersonNode returns first non-acquired partner', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const acq = new PersonNode({} as any, new MPerson('Acquired /J/'), Card.REGULAR)
    acq.acquired = true
    const main = new PersonNode({} as any, new MPerson('Main /J/'), Card.REGULAR)
    fn.partners = [acq, main]
    assert.equal(fn.getMainPersonNode(), main)
  })

  it('FamilyNode getMainPersonNode returns null if all acquired', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const a1 = new PersonNode({} as any, new MPerson('A1 /J/'), Card.REGULAR)
    a1.acquired = true
    fn.partners = [a1]
    assert.equal(fn.getMainPersonNode(), null)
  })

  it('FamilyNode hasChildren returns true when youth is not null', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    assert.equal(fn.hasChildren(), false, 'no children initially')
    fn.youth = {} as any
    assert.ok(fn.hasChildren(), 'has children when youth set')
  })

  it('FamilyNode hasChildren returns true when mini', () => {
    const fn = new FamilyNode({} as any, true, 0 as any, false)
    assert.ok(fn.hasChildren(), 'mini always has children')
  })

  it('FamilyNode getPartner returns partner at index', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const p0 = new PersonNode({} as any, new MPerson('P0 /K/'), Card.REGULAR)
    const p1 = new PersonNode({} as any, new MPerson('P1 /K/'), Card.REGULAR)
    fn.partners = [p0, p1]
    assert.equal(fn.getPartner(0), p0)
    assert.equal(fn.getPartner(1), p1)
    assert.equal(fn.getPartner(2), null)
  })

  it('Bond centerX is x + width/2', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const bond = new Bond(fn)
    bond.x = 10
    bond.width = 20
    assert.equal(bond.centerX(), 20)
  })

  it('Bond marriageYear returns last word of marriageDate', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const bond = new Bond(fn)
    bond.marriageDate = '15 JUN 1990'
    assert.equal(bond.marriageYear(), ' 1990')
  })

  it('Bond marriageYear returns empty string for null date', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const bond = new Bond(fn)
    assert.equal(bond.marriageYear(), '')
  })

  it('Bond toString returns year or hearth symbol', () => {
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    const bond = new Bond(fn)
    assert.equal(bond.toString(), '-•-')
    bond.marriageDate = '1 JAN 2000'
    assert.ok(bond.toString().includes('2000'))
  })

  it('Node getOrigin returns origin for PersonNode', () => {
    const pn = new PersonNode({} as any, new MPerson('Origin /L/'), Card.REGULAR)
    const parent = new PersonNode({} as any, new MPerson('Parent /L/'), Card.REGULAR)
    pn.origin = parent
    assert.equal(pn.getOrigin(), parent)
  })

  it('Node isMultiMarriage returns true for NEAR/MIDDLE/FAR', () => {
    const pn = new PersonNode({} as any, new MPerson('MM /M/'), Card.REGULAR)
    pn.match = Match.MAIN
    assert.equal(pn.isMultiMarriage(), false)
    pn.match = Match.NEAR
    assert.ok(pn.isMultiMarriage(), 'NEAR is multi')
    pn.match = Match.MIDDLE
    assert.ok(pn.isMultiMarriage(), 'MIDDLE is multi')
    pn.match = Match.FAR
    assert.ok(pn.isMultiMarriage(), 'FAR is multi')
  })

  it('PersonNode isDuplicate returns duplicate field', () => {
    const pn = new PersonNode({} as any, new MPerson('Dup /N/'), Card.REGULAR)
    assert.equal(pn.isDuplicate(), false)
    pn.duplicate = true
    assert.ok(pn.isDuplicate())
  })

  it('PersonNode getOrigins returns single-element array when origin set', () => {
    const parent = new PersonNode({} as any, new MPerson('Parent /O/'), Card.REGULAR)
    const child = new PersonNode({} as any, new MPerson('Child /O/'), Card.REGULAR)
    child.origin = parent
    const origins = child.getOrigins()
    assert.equal(origins.length, 1)
    assert.equal(origins[0], parent)
  })

  it('PersonNode getOrigins returns empty when origin null', () => {
    const pn = new PersonNode({} as any, new MPerson('NoOrigin /P/'), Card.REGULAR)
    assert.equal(pn.getOrigins().length, 0)
  })

  it('PersonNode getFamilyNode returns familyNode or self', () => {
    const pn = new PersonNode({} as any, new MPerson('FN /Q/'), Card.REGULAR)
    assert.equal(pn.getFamilyNode(), pn)
    const fn = new FamilyNode({} as any, false, 0 as any, false)
    pn.familyNode = fn
    assert.equal(pn.getFamilyNode(), fn)
  })

  it('PersonNode getMainPersonNode returns null for half sibling', () => {
    const pn = new PersonNode({} as any, new MPerson('Half /R/'), Card.REGULAR)
    pn.isHalfSibling = true
    assert.equal(pn.getMainPersonNode(), null)
  })
})

import { Person, Family, Gedcom, Name, EventFact, FamilyRef } from '../model/types'

let nextId = 1
export function resetIds(): void {
  nextId = 1
}
export function uid(): string {
  return `@I${nextId++}@`
}
export function fid(): string {
  return `@F${nextId++}@`
}

export class MName implements Name {
  constructor(private value: string) {}
  getDisplayValue(): string {
    return this.value
  }
  getGiven(): string {
    return ''
  }
  getSurname(): string {
    return ''
  }
  getNickname(): string {
    return ''
  }
}

export class MFact implements EventFact {
  constructor(
    private tag: string,
    private value: string | null = null,
    private date: string | null = null,
  ) {}
  getTag(): string | null {
    return this.tag
  }
  getValue(): string | null {
    return this.value
  }
  getDate(): string | null {
    return this.date
  }
  getPlace(): string | null {
    return null
  }
}

export class MRef implements FamilyRef {
  ref: string
  person: Person | null
  constructor(ref: string, person: Person | null) {
    this.ref = ref
    this.person = person
  }
  getFamily(_g: Gedcom): Family | null {
    return null
  }
  getPerson(_g: Gedcom): Person | null {
    return this.person
  }
}

export class MPerson implements Person {
  id: string
  private _names: Name[]
  private _facts: EventFact[]
  private _parentFams: Family[]
  private _spouseFams: Family[]
  constructor(name: string, facts?: EventFact[], parentFams?: Family[], spouseFams?: Family[]) {
    this.id = uid()
    this._names = [new MName(name)]
    this._facts = facts ?? []
    this._parentFams = parentFams ?? []
    this._spouseFams = spouseFams ?? []
  }
  getId(): string {
    return this.id
  }
  getNames(): Name[] {
    return this._names
  }
  getEventsFacts(): EventFact[] {
    return this._facts
  }
  getParentFamilies(_g?: Gedcom): Family[] {
    return this._parentFams
  }
  getSpouseFamilies(_g?: Gedcom): Family[] {
    return this._spouseFams
  }
}

export class MFamily implements Family {
  id: string
  private _husbands: Person[]
  private _wives: Person[]
  private _children: Person[]
  private _facts: EventFact[]
  constructor(husbands: Person[], wives: Person[], children: Person[], facts?: EventFact[]) {
    this.id = fid()
    this._husbands = husbands
    this._wives = wives
    this._children = children
    this._facts = facts ?? []
    for (const p of [...husbands, ...wives]) {
      const p2 = p as MPerson
      ;(p2 as any)._spouseFams = [...(p2 as any)._spouseFams, this]
    }
    for (const c of children) {
      const c2 = c as MPerson
      ;(c2 as any)._parentFams = [...(c2 as any)._parentFams, this]
    }
  }
  getId(): string {
    return this.id
  }
  getHusbandRefs(): FamilyRef[] {
    return this._husbands.map(p => new MRef(p.getId(), p))
  }
  getWifeRefs(): FamilyRef[] {
    return this._wives.map(p => new MRef(p.getId(), p))
  }
  getSpouseRefs(): FamilyRef[] {
    return []
  }
  getParentRefs(): FamilyRef[] {
    return []
  }
  getHusbands(_gedcom?: Gedcom): Person[] {
    return [...this._husbands]
  }
  getWives(_gedcom?: Gedcom): Person[] {
    return [...this._wives]
  }
  getChildren(_gedcom?: Gedcom): Person[] {
    return [...this._children]
  }
  getEventsFacts(): EventFact[] {
    return this._facts
  }
}

export class MGedcom implements Gedcom {
  people: Map<string, Person>
  families: Map<string, Family>
  constructor(people: Person[], families: Family[]) {
    this.people = new Map(people.map(p => [p.getId(), p]))
    this.families = new Map(families.map(f => [f.getId(), f]))
  }
  getPerson(id: string): Person | null {
    return this.people.get(id) ?? null
  }
  getPeople(): Person[] {
    return [...this.people.values()]
  }
  getFamilies(): Family[] {
    return [...this.families.values()]
  }
}

import { Graph } from '../engine/Graph'

export function build(...people: MPerson[]): { gedcom: MGedcom; fulcrum: MPerson; graph: Graph } {
  const allFams = new Set<Family>()
  for (const p of people) {
    for (const f of p.getParentFamilies()) allFams.add(f)
    for (const f of p.getSpouseFamilies()) allFams.add(f)
  }
  const gedcom = new MGedcom(people, [...allFams])
  const fulcrum = people[0]
  const graph = new Graph()
  graph.setGedcom(gedcom)
  return { gedcom, fulcrum, graph }
}

export function run(graph: Graph, fulcrum: Person): void {
  graph.startFrom(fulcrum)
  graph.initNodes()
  graph.placeNodes()
}

export function hasFinitePos(n: { x: number; y: number; width: number; height: number }): boolean {
  return isFinite(n.x) && isFinite(n.y) && isFinite(n.width) && isFinite(n.height)
}

import type { Gedcom, Family, Person } from '../model/types'
import type { Node } from '../core/Node'
import { FamilyNode } from '../nodes/FamilyNode'
import { PersonNode } from '../nodes/PersonNode'
import { Group } from '../layout/Group'
import type { Bond } from '../nodes/Bond'
import { DuplicateLine } from '../lines/DuplicateLine'
import type { Line } from '../core/Line'
import { Animator } from './Animator'
import { TreeWalker } from './TreeWalker'
import {
  Card,
  Match,
  Side,
  Branch,
  VERTICAL_SPACE,
  LITTLE_GROUP_DISTANCE,
  setVerticalSpaceCalc,
  setLittleGroupDistanceCalc,
} from '../config/Util'

export class Graph {
  fulcrum: Person | null = null
  whichFamily = 0

  ancestorGenerations = 3
  greatUnclesGenerations = 2
  withSpouses = true
  descendantGenerations = 3
  siblingNephewGenerations = 2
  uncleCousinGenerations = 2
  withNumbers = true
  withDuplicateLines = true

  gedcom!: Gedcom
  readonly animator: Animator
  fulcrumGroup!: Group
  maxAbove = 0
  maxBelow = 0
  leftToRight = false

  constructor() {
    this.animator = new Animator()
  }

  setGedcom(gedcom: Gedcom): this {
    this.gedcom = gedcom
    return this
  }

  showFamily(num: number): this {
    this.whichFamily = num
    return this
  }

  maxAncestors(num: number): this {
    this.ancestorGenerations = num
    return this
  }

  maxGreatUncles(num: number): this {
    this.greatUnclesGenerations = num
    return this
  }

  displaySpouses(display: boolean): this {
    this.withSpouses = display
    return this
  }

  maxDescendants(num: number): this {
    this.descendantGenerations = num
    return this
  }

  maxSiblingsNephews(num: number): this {
    this.siblingNephewGenerations = num
    return this
  }

  maxUnclesCousins(num: number): this {
    this.uncleCousinGenerations = num
    return this
  }

  displayNumbers(display: boolean): this {
    this.withNumbers = display
    setVerticalSpaceCalc(display ? VERTICAL_SPACE : VERTICAL_SPACE / 2)
    setLittleGroupDistanceCalc(display ? LITTLE_GROUP_DISTANCE : LITTLE_GROUP_DISTANCE / 2)
    return this
  }

  displayDuplicateLines(display: boolean): this {
    this.withDuplicateLines = display
    return this
  }

  setLayoutDirection(leftToRight: boolean): this {
    this.leftToRight = leftToRight
    this.animator.leftToRight = leftToRight
    return this
  }

  getWidth(): number {
    return this.animator.width
  }
  getHeight(): number {
    return this.animator.height
  }

  getPersonNodes(): PersonNode[] {
    return this.animator.personNodes
  }
  getBonds(): Bond[] {
    return this.animator.bonds
  }

  needMaxBitmapSize(): boolean {
    return this.animator.maxBitmapSize === 0
  }

  setMaxBitmapSize(size: number): void {
    this.animator.maxBitmapSize = size
  }
  getMaxBitmapSize(): number {
    return this.animator.maxBitmapSize
  }
  getBiggestPathSize(): number {
    return this.animator.biggestPathSize
  }

  getLines(): Set<Line>[] {
    return this.animator.lineGroups
  }
  getBackLines(): Set<Line>[] {
    return this.animator.backLineGroups
  }
  getDuplicateLines(): DuplicateLine[] {
    return this.animator.duplicateLines
  }

  initNodes(): void {
    this.animator.initNodes(this.fulcrumGroup, this.maxAbove, this.maxBelow, this.withNumbers)
  }

  placeNodes(): void {
    this.animator.placeNodes()
  }

  startFrom(fulcrum: Person): void {
    this.fulcrum = fulcrum
    const walker = new TreeWalker(this)
    walker.walk(fulcrum)
  }

  createGroup(generation: number, mini: boolean, branch: Branch, beforeFulcrumGroup = false): Group {
    const group = new Group(generation, mini, branch)
    if (beforeFulcrumGroup) {
      const index = this.animator.groups.indexOf(this.fulcrumGroup)
      this.animator.groups.splice(index, 0, group)
    } else {
      this.animator.groups.push(group)
    }
    return group
  }

  createNodeFromPerson(
    person: Person,
    spouseFamily: Family | null,
    parentNode: Node | null,
    generation: number,
    type: Card,
    match: Match,
  ): Node {
    const personNode = new PersonNode(this.gedcom, person, type)
    personNode.generation = generation
    personNode.origin = parentNode
    personNode.match = match
    this.checkForDuplicate(personNode, spouseFamily)

    let familyNode: FamilyNode | null = null
    if ((type === Card.FULCRUM || type === Card.REGULAR) && spouseFamily && !personNode.duplicate) {
      const spouses = this.getSpouses(spouseFamily, null)
      if (spouses.length > 1 && this.withSpouses) {
        familyNode = new FamilyNode(spouseFamily, false, Side.NONE, this.leftToRight)
        familyNode.generation = generation
        familyNode.match = match
        for (const spouse of spouses) {
          if (spouse.getId() === person.getId() && !familyNode.partners.includes(personNode)) {
            familyNode.addPartner(personNode)
          } else {
            const partnerNode = new PersonNode(this.gedcom, spouse, Card.REGULAR)
            partnerNode.generation = generation
            familyNode.addPartner(partnerNode)
            if (
              parentNode &&
              spouse.getParentFamilies(this.gedcom).some(f => f.getId() === parentNode.spouseFamily!.getId())
            ) {
              partnerNode.origin = parentNode
            } else {
              this.findAcquiredAncestry(partnerNode)
            }
            this.checkForDuplicate(partnerNode, spouseFamily)
          }
        }
        familyNode.createBond()
      } else {
        personNode.spouseFamily = spouseFamily
      }
    }

    if (familyNode) {
      this.animator.addNode(familyNode)
      return familyNode
    }
    this.animator.addNode(personNode)
    return personNode
  }

  createNodeFromFamily(spouseFamily: Family, generation: number, type: Card): FamilyNode {
    const newNode = new FamilyNode(spouseFamily, type === Card.ANCESTRY, Side.NONE, this.leftToRight)
    newNode.generation = generation
    if (type === Card.REGULAR || this.withNumbers) {
      newNode.match = Match.MAIN
      const spouses = this.getSpouses(spouseFamily, null)
      for (const spouse of spouses) {
        const personNode = new PersonNode(this.gedcom, spouse, type)
        personNode.generation = generation
        this.checkForDuplicate(personNode, spouseFamily)
        newNode.addPartner(personNode)
      }
    }
    newNode.createBond()
    this.animator.addNode(newNode)
    return newNode
  }

  createNextFamilyNode(
    spouseFamily: Family,
    excluded: Person,
    generation: number,
    side: Side,
    match: Match,
    parentNode: Node | null,
  ): FamilyNode {
    const familyNode = new FamilyNode(spouseFamily, false, side, this.leftToRight)
    familyNode.generation = generation
    familyNode.match = match
    if (this.withSpouses) {
      for (const partner of this.getSpouses(spouseFamily, excluded)) {
        const personNode = new PersonNode(this.gedcom, partner, Card.REGULAR)
        personNode.generation = generation
        if (
          parentNode &&
          partner.getParentFamilies(this.gedcom).some(f => f.getId() === parentNode.spouseFamily!.getId())
        ) {
          personNode.origin = parentNode
        } else {
          this.findAcquiredAncestry(personNode)
        }
        familyNode.addPartner(personNode)
        this.checkForDuplicate(personNode, spouseFamily)
      }
    }
    familyNode.createBond()
    this.animator.addNode(familyNode)
    return familyNode
  }

  getSpouses(family: Family, excluded: Person | null): Person[] {
    const spouses: Person[] = []
    const husbandRefs = family.getHusbandRefs()
    const wifeRefs = family.getWifeRefs()
    if (husbandRefs.length > 0) {
      const p = husbandRefs[0].getPerson(this.gedcom)
      if (p) spouses.push(p)
    }
    if (wifeRefs.length > 0) {
      const p = wifeRefs[0].getPerson(this.gedcom)
      if (p) spouses.push(p)
    }
    for (let i = 1; i < husbandRefs.length; i++) {
      const p = husbandRefs[i].getPerson(this.gedcom)
      if (p) spouses.push(p)
    }
    for (let i = 1; i < wifeRefs.length; i++) {
      const p = wifeRefs[i].getPerson(this.gedcom)
      if (p) spouses.push(p)
    }
    for (let i = spouses.length - 1; i >= 0; i--) {
      if (excluded && spouses[i].getId() === excluded.getId()) spouses.splice(i, 1)
    }
    if (spouses.length > 2) spouses.length = 2
    if (excluded && spouses.length === 2) spouses.length = 1
    return spouses
  }

  areSiblings(first: PersonNode | null, second: PersonNode | null): boolean {
    if (first && second) {
      const firstFamilies = first.person.getParentFamilies(this.gedcom)
      const secondFamilies = second.person.getParentFamilies(this.gedcom)
      return (
        firstFamilies.length > 0 &&
        secondFamilies.length > 0 &&
        firstFamilies[firstFamilies.length - 1].getId() === secondFamilies[secondFamilies.length - 1].getId()
      )
    }
    return false
  }

  private checkForDuplicate(newPersonNode: PersonNode, spouseFamily: Family | null): void {
    for (const oldPersonNode of this.animator.personNodes) {
      if (!newPersonNode.mini && !oldPersonNode.mini) {
        if (oldPersonNode.person.getId() === newPersonNode.person.getId()) {
          if (
            !spouseFamily ||
            !oldPersonNode.familyNode ||
            !oldPersonNode.familyNode.spouseFamily ||
            oldPersonNode.familyNode.spouseFamily.getId() === spouseFamily.getId()
          ) {
            newPersonNode.duplicate = true
          }
          if (this.withDuplicateLines) {
            this.animator.duplicateLines.push(new DuplicateLine(oldPersonNode, newPersonNode))
          }
        } else if (
          oldPersonNode.generation === newPersonNode.generation &&
          oldPersonNode.familyNode &&
          oldPersonNode.familyNode.spouseFamily &&
          spouseFamily &&
          oldPersonNode.familyNode.spouseFamily.getId() === spouseFamily.getId()
        ) {
          newPersonNode.duplicate = true
        }
      }
    }
  }

  findAcquiredAncestry(card: PersonNode): void {
    card.acquired = true
    if (this.withNumbers) {
      const parentFamilies = card.person.getParentFamilies(this.gedcom)
      if (parentFamilies.length > 0) {
        const family = parentFamilies[parentFamilies.length - 1]
        const ancestry = this.createNodeFromFamily(family, card.generation - 1, Card.ANCESTRY)
        card.origin = ancestry
        const husband = ancestry.getHusband()
        if (husband) husband.acquired = true
        const wife = ancestry.getWife()
        if (wife) wife.acquired = true
      }
    }
  }

  toString(): string {
    const lines: string[] = []
    for (const node of this.animator.nodes) {
      lines.push(node.generation + ':  | ' + String(node) + ' |')
    }
    return lines.join('\n')
  }
}

import type { Family } from '../model/types'
import { Bond } from './Bond'
import { Node } from '../core/Node'
import type { PersonNode } from './PersonNode'
import { Branch, Side, Match, MINI_BOND_WIDTH, MARRIAGE_INNER_WIDTH, BOND_WIDTH } from '../config/Util'

export class FamilyNode extends Node {
  partners: PersonNode[] = []
  bond: Bond | null = null
  side: Side
  leftToRight: boolean

  constructor(
    public spouseFamily: Family,
    mini: boolean,
    side: Side,
    leftToRight: boolean,
  ) {
    super()
    this.mini = mini
    this.side = side
    this.leftToRight = leftToRight
    this.partners = []
  }

  getOrigin(): Node | null {
    const mainPerson = this.getMainPersonNode()
    return mainPerson ? mainPerson.origin : null
  }

  getOrigins(): Node[] {
    const origins: Node[] = []
    for (const partner of this.partners) {
      if (partner.origin && !partner.origin.mini && partner.origin.getPersonNodes().length > 0)
        origins.push(partner.origin)
    }
    return origins
  }

  isDuplicate(): boolean {
    return this.partners.some(p => p.duplicate)
  }

  getFamilyNode(): Node {
    return this
  }

  getPersonNodes(): PersonNode[] {
    return this.partners
  }

  getMainPersonNode(): PersonNode | null {
    return this.partners.find(p => !p.acquired) ?? null
  }

  getHusband(): PersonNode | null {
    return this.partners[0] ?? null
  }

  getWife(): PersonNode | null {
    return this.partners.length > 1 ? this.partners[1] : (this.partners[0] ?? null)
  }

  getPartner(id: number): PersonNode | null {
    return this.partners[id] ?? null
  }

  addPartner(partner: PersonNode): void {
    this.partners.push(partner)
    partner.familyNode = this
    partner.spouseFamily = this.spouseFamily
  }

  createBond(): void {
    if (this.partners.length === 1 && this.match === Match.MAIN) return
    this.bond = new Bond(this)
    if (!this.mini && this.partners.length > 0) {
      for (const ef of this.spouseFamily.getEventsFacts()) {
        if (ef.getTag() === 'MARR') this.bond.marriageDate = ef.getDate()
      }
    }
  }

  hasChildren(): boolean {
    if (this.mini) return true
    return this.youth !== null
  }

  centerRelX(): number {
    if (this.partners.length === 0 || this.side === Side.RIGHT) return this.bond!.width / 2
    else if (this.partners.length > 1 || this.side === Side.LEFT)
      return this.partners[0].width + this.getBondWidth() / 2
    else return this.partners[0].width / 2
  }

  centerRelY(): number {
    return this.height / 2
  }

  simpleCenterX(): number {
    if (this.bond) {
      return this.bond.x + this.bond.width / 2
    }
    return this.x + this.width / 2
  }

  setX(x: number): void {
    this.force += x - this.x
    this.x = x
    if (this.partners.length === 0) {
      this.bond!.setX(x)
    } else if (this.side === Side.RIGHT) {
      this.bond!.x = x
      this.partners[0].x = x + this.bond!.width - this.bond!.overlap
    } else {
      for (let i = 0; i < this.partners.length; i++) {
        const partner = this.partners[i]
        partner.x = x
        if (i === 0) {
          x += partner.width
          if (this.bond) {
            this.bond.setX(x)
            x += this.getBondWidth()
          }
        }
      }
    }
  }

  setY(y: number): void {
    this.y = y
    for (const partner of this.partners) {
      partner.setY(this.centerY() - partner.centerRelY())
    }
    if (this.bond) this.bond.y = y
  }

  getLeftWidth(branch: Branch): number {
    if ((branch === Branch.MATER || this.partners.indexOf(this.getMainPersonNode()!) > 0) && this.partners.length > 1) {
      return this.getPartner(0)!.width + this.getBondWidth() + this.getPartner(1)!.centerRelX()
    } else if (this.partners.length > 0) {
      return this.getPartner(0)!.centerRelX()
    }
    return 0
  }

  getBondWidth(): number {
    if (this.bond) return this.mini ? MINI_BOND_WIDTH : this.bond.marriageDate ? MARRIAGE_INNER_WIDTH : BOND_WIDTH
    return 0
  }

  toString(): string {
    const parts = this.partners.map(p => String(p))
    return '{' + parts.join(', ') + '}'
  }
}

import { Metric } from '../core/Metric'
import type { FamilyNode } from './FamilyNode'

export class Bond extends Metric {
  marriageDate: string | null = null
  familyNode: FamilyNode
  overlap = 0

  constructor(familyNode: FamilyNode) {
    super()
    this.familyNode = familyNode
  }

  centerRelX(): number {
    return this.width / 2
  }
  centerRelY(): number {
    return this.height / 2
  }
  setX(x: number): void {
    this.x = x - this.overlap
  }
  setY(y: number): void {
    this.y = y
  }

  marriageYear(): string {
    if (!this.marriageDate) return ''
    const i = this.marriageDate.lastIndexOf(' ')
    return i > 0 ? this.marriageDate.substring(i) : this.marriageDate
  }

  toString(): string {
    const txt = this.marriageYear()
    return txt || '-•-'
  }
}

export abstract class Metric {
  x = 0
  y = 0
  width = 0
  height = 0

  abstract centerRelX(): number
  abstract centerRelY(): number

  centerX(): number {
    return this.x + this.centerRelX()
  }

  centerY(): number {
    return this.y + this.centerRelY()
  }

  abstract setX(x: number): void
  abstract setY(y: number): void
}

import type { Family } from '../model/types'
import { Metric } from './Metric'
import { Branch, Match, HORIZONTAL_SPACE, UNION_DISTANCE, ANCESTRY_DISTANCE, PROGENY_PLAY } from '../config/Util'
import type { Group } from '../layout/Group'
import type { Union } from '../layout/Union'
import { FamilyNode } from '../nodes/FamilyNode'
import type { PersonNode } from '../nodes/PersonNode'

export abstract class Node extends Metric {
  spouseFamily: Family | null = null
  group: Group | null = null
  youth: Group | null = null
  generation = 0
  mini = false
  isAncestor = false
  marriedSiblings = false
  union: Union | null = null
  prev: Node | null = null
  next: Node | null = null
  match: Match = Match.MAIN
  origins: Node[] | null = null
  force = 0
  columnShift = 0

  abstract getLeftWidth(branch: Branch): number
  abstract simpleCenterX(): number

  moveDescending(shift: number): void {
    this.setX(this.x + shift)
    if (this.youth) {
      for (const child of this.youth.list) {
        child.moveDescending(shift)
      }
    }
  }

  placeYouthX(): void {
    if (this.youth && !this.youth.mini) {
      this.youth.placeNodes(this.centerX())
    }
  }

  placeMiniChildrenX(): void {
    if (this.youth && this.youth.mini) {
      let posX = this.centerX()
      for (const child of this.youth.list) {
        child.x = posX
        posX += child.width + PROGENY_PLAY
      }
      this.youth.updateX()
      this.youth.setX(this.youth.x - this.youth.getWidth() / 2)
    }
  }

  placeAcquiredOriginX(): void {
    if (this instanceof FamilyNode) {
      for (const partner of (this as FamilyNode).partners) {
        if (partner.acquired && partner.origin) {
          partner.origin.setX(partner.centerX() - partner.origin.centerRelX())
        }
      }
    }
  }

  placeAcquiredOriginY(): void {
    if (this instanceof FamilyNode && !this.mini) {
      for (const partner of (this as FamilyNode).partners) {
        if (partner.acquired && partner.origin) {
          partner.origin.setY(partner.y - ANCESTRY_DISTANCE - partner.origin.height)
        }
      }
    }
  }

  alignMiniEmptyOverYouth(): void {
    if (this.youth && this.youth.isOriginMiniOrEmpty()) {
      this.youth.updateX()
      this.setX(this.youth.centerX() - this.centerRelX())
    }
  }

  slide(shift: number): void {
    this.setX(this.x + shift)
    if (shift > 0 && this.next) {
      const rightOver =
        this.x + this.width + (this.union === this.next.union ? HORIZONTAL_SPACE : UNION_DISTANCE) - this.next.x
      if (rightOver > 0) this.next.slide(rightOver)
    } else if (shift < 0 && this.prev) {
      const leftOver =
        this.prev.x + this.prev.width + (this.union === this.prev.union ? HORIZONTAL_SPACE : UNION_DISTANCE) - this.x
      if (leftOver > 0) this.prev.slide(-leftOver)
    }
  }

  abstract getOrigin(): Node | null
  abstract getOrigins(): Node[]
  abstract isDuplicate(): boolean
  abstract getFamilyNode(): Node
  abstract getPersonNodes(): PersonNode[]
  abstract getMainPersonNode(): PersonNode | null
  abstract getHusband(): PersonNode | null
  abstract getWife(): PersonNode | null
  abstract getPartner(id: number): PersonNode | null

  isMultiMarriage(): boolean {
    return this.match === Match.FAR || this.match === Match.MIDDLE || this.match === Match.NEAR
  }

  initializeOrigins(): void {
    if (this.generation >= -1 && !this.mini) {
      this.origins = []
      let node: Node | null = this as Node
      while (node && node.generation >= 0) {
        node = node.group ? node.group.origin : null
        if (node && !node.mini) this.origins.push(node)
      }
    }
  }

  outdistanceDescendantColumn(): void {
    if (this.youth && !this.youth.mini) {
      this.columnShift = 0
      if (this.prev && this.union === this.prev.union) {
        this.columnShift = this.prev.x + this.prev.width + HORIZONTAL_SPACE - this.x
      }
      this.findDescendantColumnShift(this)
      if (this.columnShift !== 0) {
        this.moveDescending(this.columnShift)
      }
    }
  }

  private findDescendantColumnShift(node: Node): void {
    if (node.youth && !node.youth.mini) {
      const first = node.youth.list[0]
      if (first.prev && first.prev.origins && !first.prev.origins.includes(this)) {
        const leftShift = first.prev.x + first.prev.width + UNION_DISTANCE - first.x
        if (leftShift > this.columnShift) {
          this.columnShift = leftShift
        }
      }
      for (const youthNode of node.youth.list) {
        this.findDescendantColumnShift(youthNode)
      }
    }
  }
}

import type { Person } from '../model/types'

export enum Card {
  FULCRUM,
  REGULAR,
  ANCESTRY,
  PROGENY,
}

export enum Match {
  MAIN,
  NEAR,
  MIDDLE,
  FAR,
}

export enum Branch {
  NONE,
  PATER,
  MATER,
}

export enum Side {
  NONE,
  LEFT,
  RIGHT,
}

export enum Gender {
  NONE,
  MALE,
  FEMALE,
  UNDEFINED,
  OTHER,
}

export namespace Match {
  export function get(totFamilies: number, index: number, side: Side, straight: boolean): Match {
    if (side === Side.RIGHT) {
      if (index === 0) return Match.MAIN
      if (index === 1 && straight) return Match.NEAR
      if (index === totFamilies - 1) return Match.FAR
    } else {
      if (index === totFamilies - 1) return Match.MAIN
      if (index === totFamilies - 2 && straight) return Match.NEAR
      if (index === 0) return Match.FAR
    }
    return Match.MIDDLE
  }

  export function getForAncestors(totFamilies: number, index: number, side: Side): Match {
    if ((side === Side.LEFT && index === totFamilies - 1) || (side === Side.RIGHT && index === 0)) return Match.NEAR
    if ((side === Side.LEFT && index === 0) || (side === Side.RIGHT && index === totFamilies - 1)) return Match.FAR
    return Match.MIDDLE
  }
}

export namespace Gender {
  export function getGender(person: Person): Gender {
    for (const fact of person.getEventsFacts()) {
      if (fact.getTag() === 'SEX' && fact.getValue() != null) {
        switch (fact.getValue()) {
          case 'M':
            return Gender.MALE
          case 'F':
            return Gender.FEMALE
          case 'U':
            return Gender.UNDEFINED
          default:
            return Gender.OTHER
        }
      }
    }
    return Gender.NONE
  }

  export function isMale(person: Person): boolean {
    return getGender(person) === Gender.MALE
  }

  export function isFemale(person: Person): boolean {
    return getGender(person) === Gender.FEMALE
  }
}

export const VERTICAL_SPACE = 90
export let VERTICAL_SPACE_CALC = 0
export function setVerticalSpaceCalc(v: number) {
  VERTICAL_SPACE_CALC = v
}
export const HORIZONTAL_SPACE = 15
export const UNION_DISTANCE = 35

export const BOND_WIDTH = 23
export const MINI_BOND_WIDTH = 18
export const MARRIAGE_WIDTH = 39
export const MARRIAGE_INNER_WIDTH = 25
export const MARRIAGE_HEIGHT = 25
export const HEARTH_DIAMETER = 8
export const MINI_HEARTH_DIAMETER = 6

export const LITTLE_GROUP_DISTANCE = 60
export let LITTLE_GROUP_DISTANCE_CALC = 0
export function setLittleGroupDistanceCalc(v: number) {
  LITTLE_GROUP_DISTANCE_CALC = v
}
export const ANCESTRY_DISTANCE = 16
export const PROGENY_DISTANCE = 16
export const PROGENY_PLAY = 12

export function essence(person: Person | null): string {
  if (!person) return '[No name]'
  const names = person.getNames()
  if (names.length > 0) {
    let str = names[0].getDisplayValue().replace(/\//g, '')
    str = str.trim()
    if (str) return str
  }
  return '[No name]'
}

import type { Gedcom, Person } from '../model/types'
import { Node } from '../core/Node'
import type { FamilyNode } from './FamilyNode'
import { Branch, Card, essence } from '../config/Util'

export class PersonNode extends Node {
  private gedcom: Gedcom
  person: Person
  origin: Node | null = null
  familyNode: FamilyNode | null = null
  type: Card
  acquired = false
  dead = false
  amount = 0
  duplicate = false
  isHalfSibling = false

  constructor(gedcom: Gedcom, person: Person, type: Card) {
    super()
    this.gedcom = gedcom
    this.person = person
    this.type = type
    if (type === Card.FULCRUM || type === Card.REGULAR) {
      if (this.isDead()) this.dead = true
    } else if (type === Card.ANCESTRY) {
      this.amount = 1
      this.countAncestors(person)
      this.mini = true
    } else if (type === Card.PROGENY) {
      this.amount = 1
      this.countDescendants(person)
      this.mini = true
    }
  }

  getOrigin(): Node | null {
    return this.origin
  }

  getOrigins(): Node[] {
    return this.origin ? [this.origin] : []
  }

  isDuplicate(): boolean {
    return this.duplicate
  }

  getFamilyNode(): Node {
    return this.familyNode ?? this
  }

  getPersonNodes(): PersonNode[] {
    return [this]
  }

  getMainPersonNode(): PersonNode | null {
    return this.isHalfSibling ? null : this
  }

  getHusband(): PersonNode | null {
    return this.familyNode ? this.familyNode.getHusband() : this
  }

  getWife(): PersonNode | null {
    return this.familyNode ? this.familyNode.getWife() : this
  }

  getPartner(id: number): PersonNode | null {
    if (this.familyNode) return this.familyNode.getPartner(id)
    else if (id === 0) return this
    return null
  }

  private countAncestors(ancestor: Person): void {
    if (this.amount <= 100) {
      for (const family of ancestor.getParentFamilies(this.gedcom)) {
        for (const father of family.getHusbands(this.gedcom)) {
          this.amount++
          this.countAncestors(father)
        }
        for (const mother of family.getWives(this.gedcom)) {
          this.amount++
          this.countAncestors(mother)
        }
      }
    }
  }

  private countDescendants(person: Person): void {
    if (this.amount <= 100) {
      for (const family of person.getSpouseFamilies(this.gedcom)) {
        for (const child of family.getChildren(this.gedcom)) {
          this.amount++
          this.countDescendants(child)
        }
      }
    }
  }

  private isDead(): boolean {
    for (const fact of this.person.getEventsFacts()) {
      if (fact.getTag() === 'DEAT' || fact.getTag() === 'BURI') return true
    }
    return false
  }

  isFulcrumNode(): boolean {
    return this.type === Card.FULCRUM
  }

  centerRelX(): number {
    return this.width / 2
  }
  centerRelY(): number {
    return this.height / 2
  }
  simpleCenterX(): number {
    return this.x + this.width / 2
  }

  setX(x: number): void {
    this.force += x - this.x
    this.x = x
  }

  setY(y: number): void {
    this.y = y
  }

  getLeftWidth(_branch: Branch): number {
    return this.centerRelX()
  }

  toString(): string {
    if (this.mini) {
      return `${this.amount} (${essence(this.person)})`
    }
    let txt = ' ' + essence(this.person)
    if (this.duplicate) txt += ' (2)'
    return txt.trim()
  }
}

import type { Person } from '../model/types'
import { Metric } from '../core/Metric'
import type { Node } from '../core/Node'
import type { PersonNode } from '../nodes/PersonNode'
import { Branch, HORIZONTAL_SPACE, ANCESTRY_DISTANCE, LITTLE_GROUP_DISTANCE_CALC } from '../config/Util'

export class Group extends Metric {
  list: Node[] = []
  origin: Node | null = null
  first: PersonNode | null = null
  last: PersonNode | null = null
  generation: number
  mini: boolean
  branch: Branch

  constructor(generation: number, mini: boolean, branch: Branch) {
    super()
    this.generation = generation
    this.mini = mini
    this.branch = branch
    this.list = []
  }

  addNode(node: Node, index = -1): void {
    if (index >= 0) this.list.splice(index, 0, node)
    else this.list.push(node)
    node.group = this
  }

  setOrigin(): void {
    let found = false
    for (const node of this.list) {
      if (node.isAncestor && node.getPersonNodes().length > 1) {
        this.origin = node.getPartner(this.branch === Branch.MATER ? 1 : 0)!.getOrigin()
        found = true
      }
    }
    if (!found) {
      for (const node of this.list) {
        const personNode = node.getMainPersonNode()
        if (personNode) {
          this.origin = personNode.getOrigin()
          break
        }
      }
    }
    if (this.origin) this.origin.youth = this

    if (!this.mini) {
      outer: for (const node of this.list) {
        if (node.isAncestor && this.branch === Branch.MATER && !node.marriedSiblings) {
          this.first = node.getWife()
          break
        }
        for (const personNode of node.getPersonNodes()) {
          if (!personNode.acquired) {
            this.first = personNode
            break outer
          }
        }
      }
      outer: for (let i = this.list.length - 1; i >= 0; i--) {
        const node = this.list[i]
        if (node.isAncestor && this.branch === Branch.PATER && !node.marriedSiblings) {
          this.last = node.getHusband()
          break
        }
        const personNodes = node.getPersonNodes()
        for (let j = personNodes.length - 1; j >= 0; j--) {
          const personNode = personNodes[j]
          if (!personNode.acquired) {
            this.last = personNode
            break outer
          }
        }
      }
    }
  }

  isOriginMiniOrEmpty(): boolean {
    if (this.origin) {
      if (this.origin.isMultiMarriage()) return false
      return this.origin.mini || this.origin.getPersonNodes().length === 0
    }
    return false
  }

  contains(person: Person): boolean {
    for (const node of this.list) {
      for (const personNode of node.getPersonNodes()) {
        if (personNode.person.getId() === person.getId()) return true
      }
    }
    return false
  }

  placeNodes(centerX: number): void {
    let posX = centerX - this.getBasicLeftWidth() - this.getBasicCentralWidth() / 2
    for (const child of this.list) {
      child.setX(posX)
      posX += child.width + HORIZONTAL_SPACE
    }
  }

  placeAncestors(): void {
    if (this.origin) {
      this.placeOriginX()
      const union = this.origin.union
      if (union) {
        let posX = this.origin.x
        for (let i = union.list.indexOf(this.origin) - 1; i >= 0; i--) {
          const node = union.list[i]
          posX -= node.width + HORIZONTAL_SPACE
          node.setX(posX)
        }
        posX = this.origin.x + this.origin.width + HORIZONTAL_SPACE
        for (let i = union.list.indexOf(this.origin) + 1; i < union.list.length; i++) {
          const node = union.list[i]
          node.setX(posX)
          posX += node.width + HORIZONTAL_SPACE
        }
      }
    }
  }

  placeOriginX(): void {
    this.origin!.setX(
      this.first!.centerX() + (this.last!.centerX() - this.first!.centerX()) / 2 - this.origin!.centerRelX(),
    )
  }

  placeOriginY(): void {
    this.origin!.setY(
      this.y - (this.first === this.last ? ANCESTRY_DISTANCE : LITTLE_GROUP_DISTANCE_CALC) - this.origin!.height,
    )
  }

  moveDescending(shift: number): void {
    if (!this.mini) {
      this.updateX()
      this.setX(this.x + shift)
      for (const node of this.list) {
        if (node.youth) node.youth.moveDescending(shift)
      }
    }
  }

  centerRelX(): number {
    return this.first!.centerX() - this.x + (this.last!.centerX() - this.first!.centerX()) / 2
  }

  centerRelY(): number {
    return this.getHeight() / 2
  }

  setX(x: number): void {
    const diff = x - this.x
    for (const node of this.list) {
      node.setX(node.x + diff)
    }
    this.x = x
  }

  setY(y: number): void {
    for (const node of this.list) {
      node.setY(y)
    }
    this.y = y
  }

  updateX(): void {
    this.x = this.list[0].x
  }

  getWidth(): number {
    const lastChild = this.list[this.list.length - 1]
    this.width = lastChild.x + lastChild.width - this.x
    return this.width
  }

  private getBasicLeftWidth(): number {
    let w = 0
    for (const node of this.list) {
      if (node.getPersonNodes().includes(this.first!)) {
        w += node.getLeftWidth(this.branch)
        break
      }
      w += node.width + HORIZONTAL_SPACE
    }
    return w
  }

  private getBasicCentralWidth(): number {
    let w = 0
    if (this.first && this.first !== this.last) {
      const start = this.first.getFamilyNode()
      const end = this.last!.getFamilyNode()
      for (let i = this.list.indexOf(start); i < this.list.indexOf(end); i++) {
        w += this.list[i].width + HORIZONTAL_SPACE
      }
      w = w - start.getLeftWidth(this.branch) + end.getLeftWidth(this.branch)
    }
    return w
  }

  getHeight(): number {
    this.height = 0
    for (const node of this.list) {
      this.height = Math.max(this.height, node.height)
    }
    return this.height
  }

  toString(): string {
    return String(this.list)
  }
}

import { Line } from '../core/Line'
import type { PersonNode } from '../nodes/PersonNode'
import { Gender, VERTICAL_SPACE_CALC } from '../config/Util'

export class DuplicateLine extends Line {
  private firstNode: PersonNode
  private secondNode: PersonNode
  gender: Gender
  x3 = 0
  y3 = 0

  constructor(firstNode: PersonNode, secondNode: PersonNode) {
    super()
    this.firstNode = firstNode
    this.secondNode = secondNode
    this.gender = Gender.getGender(firstNode.person)
  }

  update(): void {
    const shift = 1.5
    if (this.firstNode.generation === this.secondNode.generation) {
      if (this.secondNode.x > this.firstNode.x) {
        this.x1 = this.firstNode.x + this.firstNode.width - shift
        this.x2 = this.secondNode.x + shift
      } else {
        this.x1 = this.firstNode.x + shift
        this.x2 = this.secondNode.x + this.secondNode.width - shift
      }
      this.y1 = this.firstNode.y + this.firstNode.height - shift
      this.y2 = this.secondNode.y + this.secondNode.height - shift
      this.x3 = this.x1 + (this.x2 - this.x1) / 2
      this.y3 = Math.max(this.y1, this.y2) + Math.min(VERTICAL_SPACE_CALC, Math.abs(this.x2 - this.x1))
    } else {
      if (this.firstNode.x < this.secondNode.x) {
        if (this.secondNode.x > this.firstNode.x + this.firstNode.width) {
          this.x1 = this.firstNode.x + this.firstNode.width - shift
          this.x2 = this.secondNode.x + shift
        } else {
          this.x1 = this.firstNode.x + (this.firstNode.width / 4) * 3
          this.x2 = this.secondNode.x + this.secondNode.width / 4
        }
      } else {
        if (this.firstNode.x > this.secondNode.x + this.secondNode.width) {
          this.x1 = this.firstNode.x + shift
          this.x2 = this.secondNode.x + this.secondNode.width - shift
        } else {
          this.x1 = this.firstNode.x + this.firstNode.width / 4
          this.x2 = this.secondNode.x + (this.secondNode.width / 4) * 3
        }
      }
      if (this.firstNode.y < this.secondNode.y) {
        this.y1 = this.firstNode.y + this.firstNode.height - shift
        this.y2 = this.secondNode.y + shift
      } else {
        this.y1 = this.firstNode.y + shift
        this.y2 = this.secondNode.y + this.secondNode.height - shift
      }
      this.x3 = this.x1 + (this.x2 - this.x1) / 2
      this.y3 = this.y1 + (this.y2 - this.y1) / 2
    }
  }
}

export abstract class Line {
  x1 = 0
  y1 = 0
  x2 = 0
  y2 = 0

  abstract update(): void

  compareTo(other: Line): number {
    return Math.min(this.x1, this.x2) - Math.min(other.x1, other.x2)
  }

  toString(): string {
    return `${this.x1}/${this.y1} - ${this.x2}/${this.y2}`
  }
}

import type { Node } from '../core/Node'
import type { PersonNode } from '../nodes/PersonNode'
import type { Bond } from '../nodes/Bond'
import { Line } from '../core/Line'
import type { DuplicateLine } from '../lines/DuplicateLine'
import { Group } from '../layout/Group'
import { GroupRow } from '../layout/GroupRow'
import { UnionRow } from '../layout/UnionRow'
import { Union } from '../layout/Union'
import { FamilyNode } from '../nodes/FamilyNode'
import {
  MINI_BOND_WIDTH,
  MARRIAGE_WIDTH,
  MARRIAGE_INNER_WIDTH,
  BOND_WIDTH,
  VERTICAL_SPACE_CALC,
  PROGENY_DISTANCE,
} from '../config/Util'
import { CurveLine } from '../lines/CurveLine'
import { NextLine } from '../lines/NextLine'
import { HorizontalLine } from '../lines/HorizontalLine'
import { BackLine } from '../lines/BackLine'
import { VerticalLine } from '../lines/VerticalLine'
import { Match, Side } from '../config/Util'

export class Animator {
  width = 0
  height = 0
  fulcrumGroup!: Group
  maxAbove = 0
  nodes: Node[] = []
  personNodes: PersonNode[] = []
  bonds: Bond[] = []
  lines: Line[] = []
  lineRows: LineRow[] = []
  lineGroups: Set<Line>[] = []
  backLines: Line[] = []
  backLineRows: LineRow[] = []
  backLineGroups: Set<Line>[] = []
  duplicateLines: DuplicateLine[] = []
  groups: Group[] = []
  groupRows: GroupRow[] = []
  unionRows: UnionRow[] = []
  leftToRight = false
  maxBitmapSize = 0
  biggestPathSize = 0

  addNode(newNode: Node): void {
    this.nodes.push(newNode)
    this.personNodes.push(...newNode.getPersonNodes())
  }

  initNodes(fulcrumGroup: Group, maxAbove: number, maxBelow: number, withNumbers: boolean): void {
    this.fulcrumGroup = fulcrumGroup
    this.maxAbove = maxAbove
    this.width = 0
    this.height = 0
    this.biggestPathSize = 0

    const totalRows = maxAbove + 1 + maxBelow
    const rowMaxHeight: number[] = new Array(totalRows).fill(0)

    for (const node of this.nodes) {
      if (node instanceof FamilyNode) {
        const familyNode = node as FamilyNode
        for (const partner of familyNode.partners) {
          familyNode.width += partner.width
          familyNode.height = Math.max(familyNode.height, partner.height)
        }
        if (familyNode.height === 0) familyNode.height = 20
        const bond = familyNode.bond
        if (bond) {
          bond.width = familyNode.mini ? MINI_BOND_WIDTH : bond.marriageDate ? MARRIAGE_WIDTH : BOND_WIDTH
          bond.height = familyNode.height
          if (bond.marriageDate) {
            bond.overlap = (MARRIAGE_WIDTH - MARRIAGE_INNER_WIDTH) / 2
            if (familyNode.side === Side.LEFT || familyNode.side === Side.RIGHT) familyNode.width += bond.overlap
          }
          this.bonds.push(bond)
          familyNode.width += familyNode.getBondWidth()
        }
      }
      if (!node.mini && node.getPersonNodes().length > 0 && node.height > rowMaxHeight[node.generation + maxAbove])
        rowMaxHeight[node.generation + maxAbove] = node.height
    }

    this.unionRows = []
    this.groupRows = []
    let posY = rowMaxHeight[0] / 2
    for (let gen = -maxAbove; gen < totalRows - maxAbove; gen++) {
      this.unionRows.push(new UnionRow(gen, posY))
      this.groupRows.push(new GroupRow(gen))
      if (gen + maxAbove < totalRows - 1)
        posY += rowMaxHeight[gen + maxAbove] / 2 + VERTICAL_SPACE_CALC + rowMaxHeight[gen + maxAbove + 1] / 2
    }

    for (const group of this.groups) {
      group.setOrigin()
    }

    if (!withNumbers) {
      for (const personNode of this.personNodes) {
        const origin = personNode.origin
        if (origin && origin.mini && origin.youth && origin.youth.list.length === 1) {
          personNode.origin = null
          const idx = this.nodes.indexOf(origin)
          if (idx >= 0) this.nodes.splice(idx, 1)
          const bondIdx = this.bonds.indexOf((origin as FamilyNode).bond!)
          if (bondIdx >= 0) this.bonds.splice(bondIdx, 1)
        }
      }
    }

    this.lines = []
    this.backLines = []
    for (const node of this.nodes) {
      for (const personNode of node.getPersonNodes()) {
        if (personNode.getOrigin()) {
          this.lines.push(new CurveLine(personNode))
        }
      }
      if (node instanceof FamilyNode) {
        const familyNode = node as FamilyNode
        if (familyNode.partners.length > 0 && familyNode.match !== Match.MAIN) this.lines.push(new NextLine(familyNode))
        else if (familyNode.partners.length > 1) this.lines.push(new HorizontalLine(familyNode))
        if (familyNode.match === Match.NEAR) this.lines.push(new BackLine(familyNode))
        else if (familyNode.match === Match.MIDDLE || familyNode.match === Match.FAR)
          this.backLines.push(new BackLine(familyNode))
        if (familyNode.hasChildren() && familyNode.bond) this.lines.push(new VerticalLine(familyNode))
      }
    }

    for (const group of this.groups) {
      if (!group.mini && group.list.length > 0) {
        if (group.generation < 0 && group.list.length === 1 && group.list[0].getPersonNodes().length === 0) continue
        this.groupRows[group.generation + maxAbove].push(group)
      }
    }

    for (const row of this.groupRows) {
      let previous: Node | null = null
      for (const group of row) {
        for (const node of group.list) {
          if (node !== previous) {
            node.prev = previous
            if (node.prev) node.prev.next = node
            previous = node
          }
        }
      }
    }

    for (const groupRow of this.groupRows) {
      for (const group of groupRow) {
        const row = this.unionRows[group.generation + maxAbove]
        let union: Union | null = null
        let joinExistingGroup = false
        for (const node of group.list) {
          if (node.isAncestor) {
            for (const un of row) {
              if (node === un.ancestor) {
                union = un
                joinExistingGroup = true
                break
              }
            }
            if (!union) {
              union = new Union(node.generation)
              union.ancestor = node
            }
            break
          }
        }
        if (!union) union = new Union(group.generation)
        if (joinExistingGroup) {
          for (const node of group.list) {
            if (node !== union.ancestor) {
              union.list.push(node)
            }
          }
        } else {
          union.list.push(...group.list)
          row.addUnion(union)
        }
        for (const node of union.list) {
          node.union = union
          const main = node.getMainPersonNode()
          if (main && main.isFulcrumNode()) union.ancestor = node
        }
      }
    }

    for (const unionRow of this.unionRows) {
      unionRow.findCentralNode()
      let previous: Union | null = null
      for (const union of unionRow) {
        union.prev = previous
        if (union.prev) union.prev.next = union
        previous = union
        union.initializeDescendants()
        union.initializeYouths()
      }
    }

    for (const node of this.nodes) {
      node.initializeOrigins()
    }
  }

  placeNodes(): void {
    for (const row of this.unionRows) {
      for (const union of row) {
        union.y = row.yAxe - union.centerRelY()
        for (const node of union.list) {
          node.setY(row.yAxe - node.centerRelY())
        }
      }
    }

    for (const group of this.groups) {
      if (!group.mini && group.isOriginMiniOrEmpty()) {
        group.y = this.unionRows[group.generation + this.maxAbove].yAxe - group.centerRelY()
        group.placeOriginY()
      }
      for (const node of group.list) {
        node.placeAcquiredOriginY()
        const youth = node.youth
        if (youth && youth.mini) youth.setY(node.y + node.height + PROGENY_DISTANCE)
      }
    }

    this.fulcrumGroup.placeNodes(0)
    for (let r = this.maxAbove; r >= 0; r--) {
      this.groupRows[r].placeAncestors()
    }
    for (let r = Math.max(0, this.maxAbove - 1); r < this.unionRows.length; r++) {
      this.unionRows[r].placeYouths()
    }
    for (let r = this.maxAbove - 1; r >= 0; r--) {
      this.unionRows[r].placeOriginsAscending()
    }

    let count = 100
    let forces = Number.MAX_VALUE
    while (count > 0 && Math.abs(forces) > 1) {
      for (const node of this.nodes) node.force = 0
      for (let r = this.maxAbove - 1; r >= 0; r--) {
        this.unionRows[r].outdistanceAncestorColumns()
      }
      for (let r = this.maxAbove - 2; r >= 0; r--) {
        for (const union of this.unionRows[r]) {
          union.setX(union.x + union.alignBetweenOrigins())
        }
      }
      for (let r = Math.max(0, this.maxAbove - 1); r < this.unionRows.length; r++) {
        this.unionRows[r].outdistanceDescendantColumns()
      }
      forces = 0
      for (const node of this.nodes) forces += node.force
      count--
    }

    for (const unionRow of this.unionRows) unionRow.resolveOverlap()

    if (this.maxAbove > 0 && this.unionRows[this.maxAbove - 1].length > 0) {
      const parentUnion = this.unionRows[this.maxAbove - 1][0]
      parentUnion.moveDescending(parentUnion.alignBetweenOrigins())
    }

    for (const node of this.nodes) {
      node.alignMiniEmptyOverYouth()
      node.placeAcquiredOriginX()
      node.placeMiniChildrenX()
    }

    let minX = Number.MAX_VALUE,
      minY = Number.MAX_VALUE
    let maxX = -Number.MAX_VALUE,
      maxY = -Number.MAX_VALUE
    for (const node of this.nodes) {
      if (node.x < minX) minX = node.x
      if (node.x + node.width > maxX) maxX = node.x + node.width
      if (node.y < minY) minY = node.y
      if (node.y + node.height > maxY) maxY = node.y + node.height
    }
    this.width = maxX - minX
    this.height = maxY - minY

    for (const node of this.nodes) {
      node.setX(node.x - minX)
      node.setY(node.y - minY)
    }

    if (!this.leftToRight) {
      for (const node of this.nodes) {
        if (node instanceof FamilyNode) node.x = this.width - node.x - node.width
      }
      for (const node of this.personNodes) node.x = this.width - node.x - node.width
      for (const bond of this.bonds) bond.x = this.width - bond.x - bond.width
    }

    for (const line of this.duplicateLines) line.update()
    this.distributeLines(this.lines, this.lineRows, this.lineGroups)
    this.distributeLines(this.backLines, this.backLineRows, this.backLineGroups)
  }

  private distributeLines(lines: Line[], lineRows: LineRow[], lineGroups: Set<Line>[]): void {
    if (this.maxBitmapSize === 0) return
    for (const line of lines) line.update()
    lines.sort((a, b) => a.compareTo(b))
    for (const row of lineRows) row.reset()
    for (const line of lines) {
      const rowNum = Math.floor(line.y2 / this.maxBitmapSize)
      while (rowNum >= lineRows.length) lineRows.push(new LineRow())
      const row = lineRows[rowNum]
      const lineLeft = Math.min(line.x1, line.x2)
      if (row.length === 0 || lineLeft > row.restartX + this.maxBitmapSize) {
        row.restartX = lineLeft
        row.push(new Set<Line>())
      }
      row[row.length - 1].add(line)
      const pathWidth = Math.max(line.x1, line.x2) - row.restartX
      if (pathWidth > this.biggestPathSize) this.biggestPathSize = pathWidth
    }
    lineGroups.length = 0
    for (const row of lineRows) {
      for (const group of row) {
        if (group.size > 0) lineGroups.push(group)
      }
    }
  }
}

class LineRow extends Array<Set<Line>> {
  restartX = 0

  reset(): void {
    this.restartX = 0
    for (const group of this) group.clear()
  }
}

import { Group } from './Group'

export class GroupRow extends Array<Group> {
  generation: number

  constructor(generation: number) {
    super()
    this.generation = generation
  }

  placeAncestors(): void {
    for (const group of this) {
      group.placeAncestors()
    }
  }

  toString(): string {
    const parts = this.map(g => String(g))
    return this.generation + ': <' + parts.join(', ') + '>'
  }
}

import { Union } from './Union'
import type { Node } from '../core/Node'
import { HORIZONTAL_SPACE, UNION_DISTANCE } from '../config/Util'

export class UnionRow extends Array<Union> {
  generation: number
  yAxe: number
  central: Node | null = null

  constructor(generation: number, yAxe: number) {
    super()
    this.generation = generation
    this.yAxe = yAxe
  }

  addUnion(union: Union): void {
    this.push(union)
  }

  findCentralNode(): void {
    if (this.length === 0) return
    if (this.generation === -1) {
      this.central = this[0].ancestor
    } else {
      const list = this[Math.floor(this.length / 2)].list
      this.central = list[Math.floor(list.length / 2)]
    }
  }

  resolveOverlap(): void {
    if (!this.central) return
    let left = this.central
    while (left.prev) {
      const gap = left.union === left.prev.union ? HORIZONTAL_SPACE : UNION_DISTANCE
      const overlap = left.prev.x + left.prev.width + gap - left.x
      if (overlap > 0) left.prev.slide(-overlap)
      left = left.prev
    }
    let right = this.central!
    while (right.next) {
      const gap = right.union === right.next.union ? HORIZONTAL_SPACE : UNION_DISTANCE
      const overlap = right.x + right.width + gap - right.next.x
      if (overlap > 0) right.next.slide(overlap)
      right = right.next
    }
  }

  placeOriginsAscending(): void {
    for (const union of this) {
      union.placeOriginsAscending()
    }
  }

  outdistanceAncestorColumns(): void {
    for (const union of this) {
      union.outdistanceAncestorColumn()
    }
  }

  outdistanceDescendantColumns(): void {
    for (const union of this) {
      for (const node of union.list) {
        node.outdistanceDescendantColumn()
      }
      union.distributeNodesOverYouth()
    }
  }

  placeYouths(): void {
    for (const union of this) {
      for (const node of union.list) {
        node.placeYouthX()
      }
    }
  }

  toString(): string {
    const parts = this.map(u => String(u))
    return this.generation + ': <' + parts.join(', ') + '>'
  }
}

import { Metric } from '../core/Metric'
import type { Node } from '../core/Node'
import type { Group } from './Group'
import { HORIZONTAL_SPACE, UNION_DISTANCE } from '../config/Util'

export class Union extends Metric {
  list: Node[] = []
  generation: number
  ancestor: Node | null = null
  prev: Union | null = null
  next: Union | null = null
  descendants: Union[] | null = null
  youths: Group[] | null = null
  columnShift = 0

  constructor(generation: number) {
    super()
    this.generation = generation
    this.list = []
  }

  getOrigins(): Node[] {
    return this.ancestor ? this.ancestor.getOrigins() : []
  }

  updateX(): void {
    this.x = this.list[0].x
  }

  initializeDescendants(): void {
    if (this.generation < 0) {
      this.descendants = []
      let union: Union = this
      while (union.generation < -1) {
        union = union.ancestor!.youth!.list[0].union!
        this.descendants.push(union)
      }
    }
  }

  initializeYouths(): void {
    this.youths = []
    for (const node of this.list) {
      if (node.youth && !node.youth.mini) this.youths.push(node.youth)
    }
  }

  placeOriginsAscending(): void {
    const origins = this.getOrigins()
    if (origins.length > 1) {
      const leftUnion = origins[0].union!
      const rightUnion = origins[1].union!
      leftUnion.updateX()
      rightUnion.updateX()
      const overlap = leftUnion.x + leftUnion.getWidth() + UNION_DISTANCE - rightUnion.x
      if (overlap > 0) {
        leftUnion.moveAscending(-overlap / 2)
        rightUnion.moveAscending(overlap / 2)
      }
    }
  }

  moveAscending(shift: number): void {
    this.updateX()
    this.setX(this.x + shift)
    if (this.ancestor) {
      for (const origin of this.ancestor.getOrigins()) {
        origin.union!.moveAscending(shift)
      }
    }
  }

  moveDescending(shift: number): void {
    this.setX(this.x + shift)
    for (const node of this.list) {
      if (node.youth) node.youth.moveDescending(shift)
    }
  }

  outdistanceAncestorColumn(): void {
    if (!this.ancestor || !this.ancestor.youth) return
    this.columnShift = 0
    this.ancestor.youth.updateX()
    const youthDistance = this.ancestor.youth.centerX() - this.centerX()
    if (this.prev && this.prev.descendants![0] === this.descendants![0]) {
      const leftShift = this.prev.x + this.prev.getWidth() + UNION_DISTANCE - this.x
      this.columnShift = Math.max(leftShift, youthDistance)
    }
    if (this.next && this.next.descendants![0] === this.descendants![0]) {
      const rightShift = this.next.x - this.x - this.getWidth() - UNION_DISTANCE
      this.columnShift = Math.min(rightShift, youthDistance)
    }
    this.findAncestorColumnShift(this.ancestor!)
    if (this.columnShift !== 0) {
      this.moveAscending(this.columnShift)
    }
  }

  private findAncestorColumnShift(node: Node): void {
    for (const origin of node.getOrigins()) {
      const prev = origin.union!.prev
      if (prev && !prev.descendants!.includes(this)) {
        const leftShift = prev.x + prev.getWidth() + UNION_DISTANCE - origin.union!.x
        if (leftShift > this.columnShift) this.columnShift = leftShift
      }
      const next = origin.union!.next
      if (next && !next.descendants!.includes(this)) {
        const rightShift = next.x - origin.union!.x - origin.union!.getWidth() - UNION_DISTANCE
        if (rightShift < this.columnShift) this.columnShift = rightShift
      }
      this.findAncestorColumnShift(origin)
    }
  }

  alignBetweenOrigins(): number {
    const origins = this.getOrigins()
    if (origins.length > 1) {
      const firstOrigin = origins[0]
      const secondOrigin = origins[1]
      const origin1X = firstOrigin.centerX()
      const origin2X = secondOrigin.centerX()
      this.updateX()
      firstOrigin.youth!.updateX()
      secondOrigin.youth!.updateX()
      const youthsDistance = secondOrigin.youth!.centerX() - firstOrigin.youth!.centerX()
      const discrepancy = origin2X - origin1X - youthsDistance
      return origin1X - firstOrigin.youth!.centerRelX() - this.x + discrepancy / 2
    } else if (origins.length > 0) {
      const origin = origins[0]
      if (origin.union) {
        origin.youth!.updateX()
        return origin.centerX() - origin.youth!.centerX()
      }
    }
    return 0
  }

  distributeNodesOverYouth(): void {
    if (!this.youths || this.youths.length === 0) return
    for (const youth of this.youths) {
      youth.updateX()
      youth.origin!.setX(youth.centerX() - youth.origin!.centerRelX())
    }
    let node = this.youths[0].origin!
    while (node.prev && node.prev.union === this) {
      node.prev.setX(node.x - HORIZONTAL_SPACE - node.prev.width)
      node = node.prev
    }
    for (let i = 0; i < this.youths.length - 1; i++) {
      const left = this.youths[i].origin!
      const right = this.youths[i + 1].origin!
      node = left.next!
      while (node && node !== right) {
        const space = node.next!.x - node.prev!.x - node.prev!.width - node.width
        node.setX(node.prev!.x + node.prev!.width + space / 2)
        node = node.next!
      }
    }
    node = this.youths[this.youths.length - 1].origin!
    while (node.next && node.next.union === this) {
      node.next.setX(node.x + node.width + HORIZONTAL_SPACE)
      node = node.next
    }
  }

  centerRelX(): number {
    return this.ancestor!.centerX() - this.x
  }

  centerRelY(): number {
    return this.getHeight() / 2
  }

  setX(x: number): void {
    const diff = x - this.x
    for (const node of this.list) {
      node.setX(node.x + diff)
    }
    this.x = x
  }

  setY(y: number): void {
    for (const node of this.list) {
      node.setY(y)
    }
    this.y = y
  }

  getWidth(): number {
    const lastChild = this.list[this.list.length - 1]
    this.width = this.list.length === 1 ? lastChild.width : lastChild.x + lastChild.width - this.x
    return this.width
  }

  getHeight(): number {
    let h = 0
    for (const node of this.list) h = Math.max(h, node.height)
    return h
  }

  toString(): string {
    return String(this.list)
  }
}

import { Line } from '../core/Line'
import type { Node } from '../core/Node'
import type { PersonNode } from '../nodes/PersonNode'

export class CurveLine extends Line {
  origin: Node
  personNode: PersonNode

  constructor(personNode: PersonNode) {
    super()
    this.personNode = personNode
    this.origin = personNode.origin!
  }

  update(): void {
    this.x1 = this.origin.simpleCenterX()
    this.y1 = this.origin.y + this.origin.height
    this.x2 = this.personNode.centerX()
    this.y2 = this.personNode.y
  }
}

import { Line } from '../core/Line'
import type { Bond } from '../nodes/Bond'
import type { PersonNode } from '../nodes/PersonNode'
import type { FamilyNode } from '../nodes/FamilyNode'
import { Side } from '../config/Util'

export class NextLine extends Line {
  bond: Bond
  partner: PersonNode
  side: Side
  leftToRight: boolean

  constructor(familyNode: FamilyNode) {
    super()
    this.bond = familyNode.bond!
    this.partner = familyNode.partners[0]
    this.side = familyNode.side
    this.leftToRight = familyNode.leftToRight
  }

  update(): void {
    if (this.bond) {
      this.x1 = this.bond.centerX()
      this.y1 = this.bond.centerY()
      if (this.leftToRight) {
        this.x2 = this.side === Side.LEFT ? this.bond.x : this.partner.x
      } else {
        this.x2 = this.side === Side.RIGHT ? this.bond.x : this.partner.x
      }
      this.y2 = this.partner.centerY()
    }
  }
}

import { Line } from '../core/Line'
import type { PersonNode } from '../nodes/PersonNode'
import type { FamilyNode } from '../nodes/FamilyNode'

export class HorizontalLine extends Line {
  leftPerson: PersonNode
  rightPerson: PersonNode
  leftToRight: boolean

  constructor(familyNode: FamilyNode) {
    super()
    this.leftPerson = familyNode.partners[0]
    this.rightPerson = familyNode.partners[1]
    this.leftToRight = familyNode.leftToRight
  }

  update(): void {
    this.x1 = this.leftToRight ? this.leftPerson.x + this.leftPerson.width : this.leftPerson.x
    this.y1 = this.leftPerson.centerY()
    this.x2 = this.leftToRight ? this.rightPerson.x : this.rightPerson.x + this.rightPerson.width
    this.y2 = this.rightPerson.centerY()
  }
}

import { Line } from '../core/Line'
import type { Bond } from '../nodes/Bond'
import type { FamilyNode } from '../nodes/FamilyNode'
import { Match, Side } from '../config/Util'

export class BackLine extends Line {
  bond: Bond
  side: Side
  match: Match
  noPartners: boolean
  leftToRight: boolean
  node: FamilyNode

  constructor(familyNode: FamilyNode) {
    super()
    this.bond = familyNode.bond!
    this.side = familyNode.side
    this.match = familyNode.match
    this.noPartners = familyNode.partners.length === 0
    this.leftToRight = familyNode.leftToRight
    this.node = familyNode
  }

  update(): void {
    if (!this.bond) return
    if (this.leftToRight) {
      this.x1 = this.side === Side.LEFT ? this.node.next!.x : this.node.prev!.x + this.node.prev!.width
    } else {
      this.x1 = this.side === Side.RIGHT ? this.node.prev!.x : this.node.next!.x + this.node.next!.width
    }
    this.y1 = this.bond.centerY()
    if (this.leftToRight) {
      if (this.bond.marriageDate) {
        this.x2 = this.side === Side.LEFT ? this.bond.x + this.bond.width : this.bond.x
      } else {
        this.x2 =
          this.noPartners && this.match === Match.MIDDLE
            ? this.side === Side.LEFT
              ? this.bond.x + this.bond.overlap
              : this.bond.x + this.bond.width - this.bond.overlap
            : this.bond.centerX()
      }
    } else {
      if (this.bond.marriageDate) {
        this.x2 = this.side === Side.RIGHT ? this.bond.x + this.bond.width : this.bond.x
      } else {
        this.x2 =
          this.noPartners && this.match === Match.MIDDLE
            ? this.side === Side.RIGHT
              ? this.bond.x + this.bond.overlap
              : this.bond.x + this.bond.width - this.bond.overlap
            : this.bond.centerX()
      }
    }
    this.y2 = this.bond.centerY()
  }
}

import { Line } from '../core/Line'
import type { Bond } from '../nodes/Bond'
import type { FamilyNode } from '../nodes/FamilyNode'

export class VerticalLine extends Line {
  bond: Bond

  constructor(familyNode: FamilyNode) {
    super()
    this.bond = familyNode.bond!
  }

  update(): void {
    this.x1 = this.bond.centerX()
    this.y1 = this.bond.centerY()
    this.x2 = this.bond.centerX()
    this.y2 = this.bond.y + this.bond.height
  }
}

import type { Person, Family } from '../model/types'
import type { Graph } from './Graph'
import type { Node } from '../core/Node'
import type { PersonNode } from '../nodes/PersonNode'
import type { Group } from '../layout/Group'
import { Genus } from '../layout/Genus'
import { Card, Match, Side, Branch, Gender } from '../config/Util'

export class TreeWalker {
  private g: Graph

  constructor(graph: Graph) {
    this.g = graph
  }

  walk(fulcrum: Person): void {
    this.g.fulcrum = fulcrum

    this.g.animator.nodes.length = 0
    this.g.animator.personNodes.length = 0
    this.g.animator.bonds.length = 0
    this.g.animator.groups.length = 0
    this.g.animator.duplicateLines.length = 0
    this.g.maxAbove = 0
    this.g.maxBelow = 0

    const parentFamilies = fulcrum.getParentFamilies(this.g.gedcom)
    this.g.fulcrumGroup = this.g.createGroup(0, false, Branch.NONE)
    if (parentFamilies.length > 0) {
      if (this.g.whichFamily >= parentFamilies.length) this.g.whichFamily = parentFamilies.length - 1
      else if (this.g.whichFamily < 0) this.g.whichFamily = 0
      const parentFamily = parentFamilies[this.g.whichFamily]
      const parentMini = this.g.ancestorGenerations === 0
      let firstParentGroup: Group | null = null
      const parentNode = this.g.createNodeFromFamily(parentFamily, -1, parentMini ? Card.ANCESTRY : Card.REGULAR)
      const parentSize = parentNode.getPersonNodes().length
      const first = parentNode.getPartner(0)
      const second = parentNode.getPartner(1)
      const parentSiblings = this.g.areSiblings(first, second)
      if (parentSize > 0 && this.g.ancestorGenerations > 0) {
        parentNode.isAncestor = true
        if (parentSiblings && second) second.origin = parentNode
        firstParentGroup = this.g.createGroup(-1, parentMini, Branch.NONE)
        firstParentGroup.branch = parentSize > 1 && !parentSiblings ? Branch.PATER : Branch.NONE
        firstParentGroup.addNode(parentNode)
        if (!parentMini) this.g.maxAbove = 1
        this.findAncestors(first!, firstParentGroup, 1, parentSiblings)
        this.findUncles(first!, firstParentGroup, parentSize === 1 || parentSiblings ? Side.LEFT : Side.NONE)
        this.findAncestorGenus(first!, firstParentGroup, Side.LEFT)
        this.findHalfSiblings(first!, parentFamily, parentSize === 1 ? Side.LEFT : Side.NONE)
      }
      const fulcrumGenus = this.findPersonGenus(fulcrum, parentNode, 0, Card.FULCRUM, null)
      for (const sibling of parentFamily.getChildren(this.g.gedcom)) {
        if (sibling.getId() === fulcrum.getId()) {
          for (const node of fulcrumGenus) {
            this.g.fulcrumGroup.addNode(node)
            this.findDescendants(node, 0, this.g.descendantGenerations + 1, false)
          }
        } else if (this.g.siblingNephewGenerations > 0 && !fulcrumGenus.contains(sibling)) {
          const siblingGenus = this.findPersonGenus(sibling, parentNode, 0, Card.REGULAR, this.g.fulcrumGroup)
          for (const siblingNode of siblingGenus) {
            this.findDescendants(siblingNode, 0, this.g.siblingNephewGenerations, false)
          }
        }
      }
      if (parentSize > 0 && this.g.ancestorGenerations > 0) {
        if (!second) {
          this.findHalfSiblings(first!, parentFamily, Side.RIGHT)
          this.findUncles(first!, firstParentGroup!, Side.RIGHT)
        } else if (parentSiblings) {
          this.findHalfSiblings(second, parentFamily, Side.NONE)
          this.findAncestors(second, firstParentGroup!, 1, true)
          this.findAncestorGenus(second, firstParentGroup!, Side.RIGHT)
          this.findUncles(first!, firstParentGroup!, Side.RIGHT)
        } else {
          const secondParentGroup = this.g.createGroup(-1, parentMini, Branch.MATER)
          secondParentGroup.addNode(parentNode)
          this.findHalfSiblings(second, parentFamily, Side.NONE)
          this.findAncestors(second, secondParentGroup, 1, false)
          this.findAncestorGenus(second, secondParentGroup, Side.RIGHT)
          this.findUncles(second, secondParentGroup, Side.NONE)
        }
      }
    } else {
      const fulcrumGenus = this.findPersonGenus(fulcrum, null, 0, Card.FULCRUM, this.g.fulcrumGroup)
      for (const node of fulcrumGenus) {
        this.findDescendants(node, 0, this.g.descendantGenerations + 1, false)
      }
    }
  }

  private findAncestors(commonNode: PersonNode, group: Group, generationUp: number, siblingPartner: boolean): void {
    const partners = commonNode.getFamilyNode().getPersonNodes()
    if (siblingPartner && partners.indexOf(commonNode) === 1) {
      commonNode.origin = partners[0].origin
      return
    }
    if (commonNode.duplicate) return
    const parentFamilies = commonNode.person.getParentFamilies(this.g.gedcom)
    if (parentFamilies.length > 0) {
      const family = parentFamilies[parentFamilies.length - 1]
      const parentGen = generationUp + 1
      const parentMini = parentGen > this.g.ancestorGenerations
      const firstParentGroup = this.g.createGroup(-parentGen, parentMini, Branch.NONE)
      const parentNode = this.g.createNodeFromFamily(family, -parentGen, parentMini ? Card.ANCESTRY : Card.REGULAR)
      commonNode.origin = parentNode
      if (generationUp > 1) {
        if (commonNode.getFamilyNode().getPersonNodes().length > 1 && !siblingPartner) {
          this.findUncles(commonNode, group, Side.NONE)
        } else {
          this.findUncles(commonNode, group, Side.LEFT)
          this.findUncles(commonNode, group, Side.RIGHT)
        }
      }
      const parentSize = parentNode.getPersonNodes().length
      if (parentSize === 0) return
      parentNode.isAncestor = true
      const first = parentNode.getPartner(0)
      const second = parentSize > 1 ? parentNode.getPartner(1) : null
      const siblingParents = this.g.areSiblings(first, second)
      firstParentGroup.branch = parentSize > 1 && !siblingParents ? Branch.PATER : Branch.NONE
      firstParentGroup.addNode(parentNode)
      if (parentGen > this.g.maxAbove && !parentMini) this.g.maxAbove = parentGen
      if (generationUp < this.g.ancestorGenerations) {
        if (second) {
          this.findAncestors(first!, firstParentGroup, parentGen, siblingParents)
          this.findAncestorGenus(first!, firstParentGroup, Side.LEFT)
          if (siblingParents) {
            this.findAncestors(second, firstParentGroup, parentGen, true)
            this.findAncestorGenus(second, firstParentGroup, Side.RIGHT)
          } else {
            const secondParentGroup = this.g.createGroup(-parentGen, parentMini, Branch.MATER)
            secondParentGroup.addNode(parentNode)
            this.findAncestors(second, secondParentGroup, parentGen, false)
            this.findAncestorGenus(second, secondParentGroup, Side.RIGHT)
          }
        } else {
          this.findAncestors(first!, firstParentGroup, parentGen, false)
          this.findAncestorGenus(first!, firstParentGroup, Gender.isFemale(first!.person) ? Side.RIGHT : Side.LEFT)
        }
      }
    }
  }

  private findAncestorGenus(personNode: PersonNode, group: Group, side: Side): void {
    const genus = new Genus()
    genus.push(personNode.familyNode!)
    if (personNode.type === Card.REGULAR && this.g.withSpouses && !personNode.duplicate) {
      const families = personNode.person.getSpouseFamilies(this.g.gedcom)
      if (families.length > 1) {
        families.splice(
          families.findIndex(f => f.getId() === personNode.spouseFamily!.getId()),
          1,
        )
        const generation = personNode.generation
        for (let i = 0; i < families.length; i++) {
          const nextFamily = families[i]
          const match = Match.getForAncestors(families.length, i, side)
          const nextFamilyNode = this.g.createNextFamilyNode(
            nextFamily,
            personNode.person,
            generation,
            side,
            match,
            personNode.origin,
          )
          if (side === Side.LEFT) {
            group.addNode(nextFamilyNode, group.list.indexOf(personNode.familyNode!))
            genus.splice(genus.indexOf(personNode.familyNode!), 0, nextFamilyNode)
          } else {
            group.addNode(nextFamilyNode, group.list.indexOf(personNode.familyNode!) + genus.length)
            genus.push(nextFamilyNode)
          }
        }
        for (const node of genus) {
          if (node !== personNode.familyNode) {
            if (generation < -1) {
              if (this.g.withNumbers && -generation <= this.g.greatUnclesGenerations + 1)
                this.findDescendants(node, generation, 0, false)
            } else if (this.g.siblingNephewGenerations > 0) {
              this.findDescendants(node, -1, this.g.siblingNephewGenerations + 1, side === Side.LEFT)
            }
          }
        }
      }
    }
  }

  private findUncles(personNode: PersonNode, group: Group, side: Side): void {
    const generationUp = -personNode.generation
    if (generationUp <= this.g.greatUnclesGenerations || (generationUp === 1 && this.g.uncleCousinGenerations > 0)) {
      const origin = personNode.origin
      if (origin) {
        const branch = group.branch
        const person = personNode.person
        const uncles = origin.spouseFamily!.getChildren(this.g.gedcom)
        let start = 0
        let end = uncles.length
        if (branch === Branch.NONE) {
          if (side === Side.LEFT) end = uncles.findIndex(u => u.getId() === person.getId())
          else if (side === Side.RIGHT) start = uncles.findIndex(u => u.getId() === person.getId()) + 1
        }
        let position = 0
        for (let i = start; i < end; i++) {
          const uncle = uncles[i]
          if (!group.contains(uncle)) {
            const uncleGenus = this.findPersonGenus(uncle, origin, -generationUp, Card.REGULAR, null)
            for (const uncleNode of uncleGenus) {
              if (branch === Branch.PATER || (branch === Branch.NONE && side === Side.LEFT)) {
                group.addNode(uncleNode, position++)
              } else {
                group.addNode(uncleNode)
              }
              if (generationUp === 1) this.findDescendants(uncleNode, -1, this.g.uncleCousinGenerations, position > 0)
              else this.findDescendants(uncleNode, -generationUp, 1, false)
            }
          }
        }
      }
    }
  }

  private findHalfSiblings(parentNode: PersonNode, excluded: Family, side: Side): void {
    if (!this.g.withSpouses) {
      const halfSiblings: Person[] = []
      const families = parentNode.person.getSpouseFamilies(this.g.gedcom)
      let start = 0
      let end = families.length
      if (side === Side.LEFT) {
        end = families.indexOf(excluded)
      } else if (side === Side.RIGHT) {
        start = families.indexOf(excluded) + 1
      }
      for (let i = start; i < end; i++) {
        const family = families[i]
        if (family.getId() !== excluded.getId()) halfSiblings.push(...family.getChildren(this.g.gedcom))
      }
      for (const halfSibling of halfSiblings) {
        if (this.g.siblingNephewGenerations > 0) {
          const halfSiblingGenus = this.findPersonGenus(halfSibling, parentNode, 0, Card.REGULAR, this.g.fulcrumGroup)
          for (const halfSiblingNode of halfSiblingGenus) {
            ;(halfSiblingNode as PersonNode).isHalfSibling = true
            this.findDescendants(halfSiblingNode, 0, this.g.siblingNephewGenerations, false)
          }
        }
      }
    }
  }

  private findDescendants(commonNode: Node, startGeneration: number, maxGenerations: number, toTheLeft: boolean): void {
    if (!commonNode.isDuplicate()) {
      const children: Person[] = []
      if (commonNode.spouseFamily) {
        children.push(...commonNode.spouseFamily.getChildren(this.g.gedcom))
      } else {
        for (const family of (commonNode as PersonNode).person.getSpouseFamilies(this.g.gedcom))
          children.push(...family.getChildren(this.g.gedcom))
      }
      if (children.length > 0) {
        const childGeneration = commonNode.generation + 1
        const childMini = childGeneration >= maxGenerations + startGeneration
        if (childMini && !this.g.withNumbers) return
        if (!childMini && childGeneration > this.g.maxBelow) this.g.maxBelow = childGeneration
        const childGroup = this.g.createGroup(childGeneration, childMini, Branch.NONE, toTheLeft)
        for (const child of children) {
          if (child) {
            const childGenus = this.findPersonGenus(
              child,
              commonNode,
              childGeneration,
              childMini ? Card.PROGENY : Card.REGULAR,
              childGroup,
            )
            if (childGenus && !childMini) {
              for (const childNode of childGenus) {
                this.findDescendants(childNode, startGeneration, maxGenerations, false)
              }
            }
          }
        }
      }
    }
  }

  private findPersonGenus(
    person: Person,
    parentNode: Node | null,
    generation: number,
    type: Card,
    group: Group | null,
  ): Genus {
    const genus = new Genus()
    if (group && group.contains(person)) return genus
    const families = person.getSpouseFamilies(this.g.gedcom)
    if (families.length === 0 || !this.g.withSpouses || type === Card.PROGENY) {
      const singleNode = this.g.createNodeFromPerson(person, null, parentNode, generation, type, Match.MAIN)
      if (group) group.addNode(singleNode)
      genus.push(singleNode)
    } else {
      const side = Gender.isFemale(person) ? Side.RIGHT : Side.LEFT
      let straight = true
      if (families.length > 1) {
        if (
          (side === Side.LEFT &&
            this.g.getSpouses(families[families.length - 1], null).findIndex(p => p.getId() === person.getId()) ===
              1) ||
          (side === Side.RIGHT &&
            this.g.getSpouses(families[0], null).findIndex(p => p.getId() === person.getId()) === 0)
        ) {
          straight = false
        }
      }
      for (let i = 0; i < families.length; i++) {
        const family = families[i]
        const match = Match.get(families.length, i, side, straight)
        let partnerNode: Node
        if (match === Match.MAIN) {
          partnerNode = this.g.createNodeFromPerson(person, family, parentNode, generation, type, match)
        } else {
          partnerNode = this.g.createNextFamilyNode(family, person, generation, side, match, parentNode)
        }
        if (group) group.addNode(partnerNode)
        genus.push(partnerNode)
      }
    }
    return genus
  }
}

import type { Person } from '../model/types'
import type { Node } from '../core/Node'

export class Genus extends Array<Node> {
  contains(person: Person): boolean {
    for (const node of this) {
      for (const personNode of node.getPersonNodes()) {
        if (personNode.person.getId() === person.getId()) {
          return true
        }
      }
    }
    return false
  }

  toString(): string {
    const parts: string[] = []
    for (const node of this) {
      parts.push(String(node))
    }
    return '[' + parts.join(' - ') + ']'
  }
}
